//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Form fields (ffData: textInput/checkBox/ddList) and form-field state".
//!
//! Each `#[test]` below encodes a Word-consumption / serializer-fidelity
//! constraint mined from ISO/IEC 29500-1 §17.16 (form fields), the [MS-OI29500]
//! implementer notes, and the §A.1 normative grammar (CT_FFData, CT_FFTextInput,
//! CT_FFCheckBox, CT_FFDDList). A FAILING assertion is NOT something to make pass
//! by weakening the test: it means stemma diverges from Word on a documented
//! load-time tolerance, consumption semantic, or round-trip child ordering, i.e.
//! a real Word-compliance gap.
//!
//! Methodology (consumption vs. save): stemma round-trips UNTOUCHED ffData
//! byte-verbatim. So `reserialize()` reflects stemma's verbatim-preservation
//! contract, valid only for child/element ORDERING (Annex A sequence) and
//! structural synthesis the serializer actively performs. Word CONSUMPTION
//! semantics ("result index selects entry", "boolean is state not text") are
//! asserted on the READ side (`read_accepted`/`read_rejected().to_text()`),
//! never on the re-serialized XML.

use std::io::Read;

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: minimal-.docx plumbing ────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. Each `extra_parts` entry is a
/// `(part_path, xml)` pair (e.g. `("word/styles.xml", "<w:styles…")`) and earns
/// a content-types override keyed off its filename.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-types: defaults + document.xml override, plus one override per
    // extra part (mapping the common WordprocessingML part names).
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let content_type = match *path {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no content-type mapping for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // document.xml.rels: one relationship per extra part (styles/numbering).
    let mut doc_rel_entries = String::new();
    for (i, (path, _)) in extra_parts.iter().enumerate() {
        let (rel_type, target) = match *path {
            "word/styles.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
                "styles.xml",
            ),
            "word/numbering.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
                "numbering.xml",
            ),
            other => panic!("make_docx: no relationship mapping for extra part {other}"),
        };
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut xml = String::new();
    file.read_to_string(&mut xml).expect("read document.xml");
    xml
}

/// Parse -> serialize(default) -> return the re-serialized `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// `opensClean`: stemma's package validator reports no errors.
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule} — validate() must report no errors; got ok={} issues={:?}",
        report.ok,
        report.issues
    );
}

/// Ordered-substring check standing in for an unavailable regex crate: every
/// literal in `needles` must occur, in order, in `haystack`. This faithfully
/// encodes the "X before Y before Z" intent of the spec's `(?s)…` ordering
/// regexes (the only regex feature these specs use is sequencing).
fn assert_ordered(haystack: &str, needles: &[&str], rule: &str) {
    let mut cursor = 0usize;
    for needle in needles {
        match haystack[cursor..].find(needle) {
            Some(rel) => cursor += rel + needle.len(),
            None => panic!(
                "{rule} — expected (in order) {needles:?}; XML missing/out-of-order at {needle:?}.\nXML:\n{haystack}"
            ),
        }
    }
}

