#[test]
fn ddlist_overlong_result_index_opens_clean() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"><w:ffData><w:name w:val="Pick"/><w:enabled/><w:calcOnExit w:val="false"/><w:ddList><w:result w:val="9"/><w:listEntry w:val="One"/><w:listEntry w:val="Two"/><w:listEntry w:val="Three"/></w:ddList></w:ffData></w:fldChar></w:r><w:r><w:instrText> FORMDROPDOWN </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>One</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.16.28/§17.16.9: an out-of-range FORMDROPDOWN result index 'can be ignored' (falls back to default), so it is not a load error",
    );
}

#[test]
fn checkbox_checked_omitted_state_from_default() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"><w:ffData><w:name w:val="Agree"/><w:enabled/><w:checkBox><w:sizeAuto/><w:default w:val="true"/></w:checkBox></w:ffData></w:fldChar></w:r><w:r><w:instrText> FORMCHECKBOX </w:instrText></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:p><w:r><w:t>Yes</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.16.8/§17.16.12: a checkBox with omitted checked + a default is well-formed and conformant",
    );
    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().expect("accept-all").to_text();
    assert_eq!(
        accepted.trim(),
        "Yes",
        "ISO 29500-1 §17.16.8: the checkbox state (derived from default) is consumed state, not run text; the only visible prose is the literal run 'Yes', so no boolean may leak into the reading text"
    );
}

