    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §A.1 CT_FFCheckBox: a checkBox with a half-point size on the size branch is schema-valid and opens clean",
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"<w:size w:val="20""#),
        "ISO 29500-1 §17.16.29: size/@val is a half-point count (20 = 10pt); stemma must preserve the literal 20 verbatim, not convert it to 10 points.\nXML:\n{xml}"
    );
