#[test]
fn textinput_type_number_format_pattern_roundtrip() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"><w:ffData><w:name w:val="Amount"/><w:enabled/><w:textInput><w:type w:val="number"/><w:maxLength w:val="4"/><w:format w:val="0.00"/></w:textInput></w:ffData></w:fldChar></w:r><w:r><w:instrText> FORMTEXT </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>0.00</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.18.28 + §A.1 CT_FFTextInput: type=number is a valid ST_FFTextType enum value and children are in sequence order, so Word opens it without repair",
    );
    let xml = reserialize(&b);
    // xmlRegex <w:type...w:val="number".../>\s*<w:maxLength.../>\s*<w:format...w:val="0.00"
    assert_ordered(
        &xml,
        &[
            r#"<w:type w:val="number""#,
            "<w:maxLength",
            r#"<w:format w:val="0.00""#,
        ],
        "ISO 29500-1 §A.1 CT_FFTextInput sequence is type, default, maxLength, format; stemma must round-trip type before maxLength before format and keep the format mask verbatim",
    );
}

