#[test]
fn ddlist_result_index_overrides_default_for_displayed_selection() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"><w:ffData><w:name w:val="Pick"/><w:enabled/><w:ddList><w:result w:val="2"/><w:default w:val="1"/><w:listEntry w:val="One"/><w:listEntry w:val="Two"/><w:listEntry w:val="Three"/></w:ddList></w:ffData></w:fldChar></w:r><w:r><w:instrText> FORMDROPDOWN </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>Three</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().expect("accept-all").to_text();
    assert_eq!(
        accepted.trim(),
        "Three",
        "ISO 29500-1 §17.16.28: result=2 selects 'Three' (overriding default=1 'Two'); Word displays the cached result run, which the accept-all read projection must surface verbatim after anchor stripping"
    );
    let rejected = doc.read_rejected().expect("reject-all").to_text();
    assert_eq!(
        rejected.trim(),
        "Three",
        "ISO 29500-1 §17.16.28: no tracked changes are present, so reject-all yields the same displayed cached selection 'Three'"
    );
}
